solution_code:
#include <iostream>
#include <iomanip>

int main()
{
    int a {};
    int b {};
    std::cin >> a >> b;

    double avg { static_cast<double>(a + b) / 2 };
    std::cout << std::fixed << std::setprecision(1)
              << "Average: " << avg << '\n';
    return 0;
}

