solution_code:
#include <iostream>

int charToAscii(char c)
{
    return static_cast<int>(c);
}

int main()
{
    char c {};
    std::cin >> c;
    std::cout << "ASCII: " << charToAscii(c) << '\n';
    return 0;
}
